contract ClosedPresaleMint {
    address private immutable owner;
    enum State { CLOSED, PRESALE, PUBLIC }
    State public currentState = State.CLOSED;
    uint256 public price;
    uint256 public totalSupply;
    uint256 public maxSupply;
    mapping(address => bool) public claimedWhitelistStatus;
    bool private _locked = false; // Mutex for reentrancy guard

    event Minted(address indexed sender, uint256 amount);

    constructor(uint256 price_, uint256 maxSupply_) {
        owner = msg.sender;
        price = price_;
        maxSupply = maxSupply_;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not authorized");
        _;
    }

    modifier nonReentrant() {
        require(!_locked, "No reentrancy");
        _locked = true;
        _;
        _locked = false;
    }

    function startPresale() public onlyOwner {
        require(currentState == State.CLOSED, "Already started");
        currentState = State.PRESALE;
    }

    function startPublicSale() public onlyOwner {
        require(currentState == State.PRESALE, "Not in presale");
        currentState = State.PUBLIC;
    }

    function mintNFT() public payable nonReentrant {
        require(currentState == State.PRESALE, "Presale not active");
        require(!claimedWhitelistStatus[msg.sender], "Already claimed");
        require(totalSupply + 1 <= maxSupply, "Exceeds max supply");
        require(msg.value >= price, "Insufficient funds");

        // Update state before external call
        totalSupply += 1;
        claimedWhitelistStatus[msg.sender] = true;

        // External call after state update
        payable(owner).transfer(msg.value);

        emit Minted(msg.sender, 1);
    }

    function mintPublicNFT(uint256 amount) public payable nonReentrant {
        require(currentState == State.PUBLIC, "Public sale not active");
        require(amount > 0, "Amount must be greater than zero");
        require(msg.value >= price * amount, "Insufficient funds");
        require(totalSupply + amount <= maxSupply, "Exceeds max supply");

        // Update state before external call
        totalSupply += amount;

        // External call after state update
        payable(owner).transfer(msg.value);

        emit Minted(msg.sender, amount);
    }

    function claimedWhitelistStatus(address user) public view returns (bool) {
        return claimedWhitelistStatus[user];
    }

    function setPrice(uint256 newPrice) public onlyOwner {
        price = newPrice;
    }

    function setMaxSupply(uint256 newMaxSupply) public onlyOwner {
        require(newMaxSupply >= totalSupply, "New max supply must be greater than or equal to current supply");
        maxSupply = newMaxSupply;
    }

    function setState(State newState) public onlyOwner {
        currentState = newState;
    }
